class Solution {
    public long[] unmarkedSumArray(int[] nums, int[][] queries) {
        int[] result = new int[queries.length];
        int sum = 0;
        for (int i = 0; i < queries.length; i++) {
            int index = queries[i][0];
            int count = queries[i][1];
            for (int j = index; j < nums.length; j++) {
                if (nums[j] != sum) {
                    sum += nums[j];
                }
            }
            result[i] = sum;
            sum = 0;
        }
        return result;
    }
}
